void game_libs_func_000097B4(s32 *out, s32 *src, s32 len, s32 key) {
    s32 sum = 0;
    s32 i = 0;
    s32 *q;
    s32 chk;

    if (len / 4 > 0) {
        do {
            q = src;
            src++;
            i++;
            sum += *q;
        } while (i != len / 4);
    }
    chk = 0xF251F205 - sum;
    out[0] = chk;
    sum = chk - sum;
    out[1] = key - sum;
}
